#nullable enable // autogenerated

using System;
using System.Threading.Tasks;
using MVZ2.Managers;
using MVZ2Logic.Archive;
using MVZ2Logic.Maps;
using MVZ2Logic.Talk;
using PVZEngine;
using PVZEngine.Level;
using PVZEngine.Definitions;

namespace MVZ2.Talk
{
    public abstract class MVZ2TalkSystem : ITalkSystem
    {
        public MVZ2TalkSystem(TalkController talk)
        {
            this.talk = talk;
        }
        public Task StartSection(int section)
        {
            return talk.StartSection(section);
        }

        public void StartTalk(NamespaceID id, int section, float delay = 1, Action? onEnd = null)
        {
            talk.StartTalk(id, section, delay, onEnd);
        }

        public bool WillSkipTalk(NamespaceID id, int section)
        {
            return talk.WillSkipTalk(id, section);
        }

        public void AutoSkipTalks(NamespaceID id, int section, Action? onSkipped = null)
        {
            talk.AutoSkipTalks(id, section, onSkipped);
        }
        public abstract IArchiveInterface? GetArchive();
        public abstract IMapInterface? GetMap();
        public abstract LevelEngine? GetLevel();

        public void ShowDialog(string title, string desc, string[] options, Action<int> onSelect)
        {
            Main.Scene.ShowDialog(title, desc, options, onSelect);
        }
        protected MainManager Main => MainManager.Instance;
        protected TalkController talk;
    }
}
